import math

class RankedRetriever:
    def __init__(self, corpus: list[str]):
        self.corpus = corpus
        self.vectors = [self._encode(d) for d in corpus]

    def _encode(self, text: str) -> dict:
        vec = {}
        for w in text.lower().split():
            vec[w] = vec.get(w, 0) + 1
        return vec

    def _cosine(self, a: dict, b: dict) -> float:
        shared = set(a) & set(b)
        dot = sum(a[w] * b[w] for w in shared)
        ma = math.sqrt(sum(v**2 for v in a.values()))
        mb = math.sqrt(sum(v**2 for v in b.values()))
        return dot / (ma * mb) if ma and mb else 0.0

    def _ranked(self, query: str) -> list[dict]:
        q = self._encode(query)
        scored = [{"doc": d, "score": self._cosine(q, v)}
                  for d, v in zip(self.corpus, self.vectors)]
        return sorted(scored, key=lambda r: r["score"], reverse=True)

